/**
 * useTheme.js
 * ─────────────────────────────────────────────────────────────
 * Hook para manejar el modo claro/oscuro.
 *
 * - Lee la preferencia del sistema con `prefers-color-scheme`
 * - Persiste la elección del usuario en localStorage
 * - Aplica el atributo `data-theme` al elemento <html>
 */

import { useState, useEffect } from 'react'

const STORAGE_KEY = 'finanzas-theme'

export const useTheme = () => {
  const [theme, setTheme] = useState(() => {
    // 1. Preferencia guardada por el usuario
    const saved = localStorage.getItem(STORAGE_KEY)
    if (saved) return saved

    // 2. Preferencia del sistema operativo
    return window.matchMedia('(prefers-color-scheme: dark)').matches
      ? 'dark'
      : 'light'
  })

  useEffect(() => {
    // Aplica el tema al elemento raíz
    document.documentElement.setAttribute('data-theme', theme)
    localStorage.setItem(STORAGE_KEY, theme)
  }, [theme])

  const toggle = () => setTheme((t) => (t === 'light' ? 'dark' : 'light'))

  return { theme, toggle, isDark: theme === 'dark' }
}
